import psycopg2

def install_extensions(extension_names):
    conn = psycopg2.connect(database="mydatabase")
    cursor = conn.cursor()
    
    # Create a list of CREATE EXTENSION commands
    extension_commands = [f"CREATE EXTENSION {name}" for name in extension_names]
    
    # Execute the CREATE EXTENSION commands
    for command in extension_commands:
        cursor.execute(command)
        
    # Commit the changes
    conn.commit()
    
    # Close the connection
    conn.close()